// ============================================
// DATA PREPARATION FOR GEMINI AI MATCHING
// ============================================

const allItems = $input.all();
console.log('Total items received:', allItems.length);

// ============================================
// SEPARATE VA RECORDS (with PDFs) FROM JOB DESCRIPTION
// ============================================
let vaRecordsWithPDFs = [];
let jobDescriptionRaw = null;

allItems.forEach((item, index) => {
  const data = item.json;

  // Check if this item is from Google Docs (Job Description)
  if (data.documentId && data.content) {
    console.log(`✓ Job Description found (documentId: ${data.documentId.substring(0, 20)}...)`);
    jobDescriptionRaw = data;
    return;
  }

  // Check if this item has PDF binary data (VA Resume)
  if (item.binary && item.binary.data) {
    console.log(`✓ VA Resume PDF #${vaRecordsWithPDFs.length + 1}:`, data.candidate_name || data.resume_filename || 'Unknown');

    // Store both JSON data and binary PDF
    vaRecordsWithPDFs.push({
      json: data,
      binary: item.binary.data.data, // The actual PDF binary
      fileName: data.resume_filename || data.candidate_name || `Resume_${vaRecordsWithPDFs.length + 1}.pdf`,
      candidateName: data.candidate_name || 'Unknown Candidate'
    });
  }
});

console.log('===========================================');
console.log('VA Resumes (PDFs) found:', vaRecordsWithPDFs.length);
console.log('Job Description found:', jobDescriptionRaw ? 'Yes' : 'No');
console.log('===========================================');

// Validation
if (vaRecordsWithPDFs.length === 0) {
  throw new Error('No VA resume PDFs found. Make sure HTTP Request node is downloading PDFs correctly.');
}

if (!jobDescriptionRaw) {
  throw new Error('No Job Description found. Make sure Google Docs node is included in the merge.');
}

// ============================================
// EXTRACT JOB DESCRIPTION TEXT
// ============================================
let jobDescriptionText = jobDescriptionRaw.content || 
                         jobDescriptionRaw.text || 
                         jobDescriptionRaw.fullText || 
                         'No job description content available';

console.log('Job Description length:', jobDescriptionText.length, 'characters');

// Clean up job description (remove excessive whitespace)
jobDescriptionText = jobDescriptionText
  .replace(/\n{3,}/g, '\n\n')
  .replace(/\s{2,}/g, ' ')
  .trim();

// ============================================
// PREPARE PDFs FOR GEMINI (Base64 Encoding)
// ============================================
const candidatesWithBase64 = vaRecordsWithPDFs.map((va, index) => {
  // Convert binary to base64
  const base64PDF = va.binary.toString('base64');

  return {
    candidateNumber: index + 1,
    name: va.candidateName,
    fileName: va.fileName,
    base64PDF: base64PDF,
    fileSize: va.binary.length,
    fileSizeKB: Math.round(va.binary.length / 1024),
    // Include any additional metadata from validation
    status: va.json.extraction_status || 'unknown',
    validationPassed: va.json.validation_passed || false
  };
});

// ============================================
// CREATE GEMINI AI PROMPT
// ============================================
const geminiPrompt = `You are an expert Virtual Assistant Recruiter for Scale Virtually.

Your task: Analyze ${candidatesWithBase64.length} candidate resumes (provided as PDFs) and match them against the client's job requirements.

---

## CLIENT JOB REQUIREMENTS:

${jobDescriptionText}

---

## YOUR ANALYSIS INSTRUCTIONS:

You will receive ${candidatesWithBase64.length} PDF resumes. For EACH candidate, you must:

1. **Extract Resume Content**: Read and parse the entire PDF to extract:
   - Full name and contact information
   - Years of experience
   - Skills (technical and soft skills)
   - Work history (companies, roles, durations)
   - Education and certifications
   - Tools/software proficiency
   - Industries worked in
   - Notable achievements

2. **Evaluate Match Against Job Requirements**:
   - Calculate a Match Score (0-100%)
   - Identify Key Strengths (what makes them suitable)
   - Identify Concerns/Gaps (what they're missing)
   - Provide clear Ranking Rationale

3. **Rank All Candidates**: Order them from best match (#1) to least suitable (#${candidatesWithBase64.length})

---

## OUTPUT FORMAT (Required - JSON Array):

Return a JSON array with this exact structure:

[
  {
    "rank": 1,
    "candidateNumber": 1,
    "name": "Full Name from Resume",
    "matchScore": 85,
    "keyStrengths": [
      "Specific strength 1",
      "Specific strength 2",
      "Specific strength 3"
    ],
    "concernsGaps": [
      "Specific concern 1",
      "Specific concern 2"
    ],
    "rankingRationale": "Clear explanation of why this ranking",
    "yearsExperience": 5,
    "topSkills": ["Skill 1", "Skill 2", "Skill 3"],
    "relevantTools": ["Tool 1", "Tool 2"],
    "contactInfo": {
      "email": "email@example.com",
      "phone": "+1234567890"
    }
  }
  // ... repeat for all ${candidatesWithBase64.length} candidates
]

---

## EVALUATION PRIORITIES:

1. **Skills Match**: How well their skills align with job requirements (40%)
2. **Experience Level**: Relevance and depth of experience (30%)
3. **Tools Proficiency**: Familiarity with required software (15%)
4. **Communication Skills**: Evidence in resume quality and clarity (10%)
5. **Cultural/Industry Fit**: Experience in relevant industries (5%)

---

Begin analysis now. Return ONLY the JSON array, no markdown formatting, no explanations outside the JSON.`;

// ============================================
// PREPARE GEMINI API REQUEST PAYLOAD
// ============================================
// Gemini supports multiple documents in one request
// We'll structure the content parts for Gemini's multimodal API

const geminiContentParts = [
  {
    text: geminiPrompt
  }
];

// Add each PDF as a document part
candidatesWithBase64.forEach(candidate => {
  geminiContentParts.push({
    inline_data: {
      mime_type: "application/pdf",
      data: candidate.base64PDF
    }
  });

  // Add a text part to identify this candidate
  geminiContentParts.push({
    text: `[CANDIDATE #${candidate.candidateNumber}: ${candidate.name} - ${candidate.fileName}]`
  });
});

// ============================================
// CREATE GEMINI API REQUEST BODY
// ============================================
const geminiRequestBody = {
  contents: [
    {
      parts: geminiContentParts
    }
  ],
  generationConfig: {
    temperature: 0.2, // Lower temperature for more consistent analysis
    topK: 40,
    topP: 0.95,
    maxOutputTokens: 8192,
    responseMimeType: "application/json" // Request JSON response
  },
  safetySettings: [
    {
      category: "HARM_CATEGORY_HARASSMENT",
      threshold: "BLOCK_NONE"
    },
    {
      category: "HARM_CATEGORY_HATE_SPEECH",
      threshold: "BLOCK_NONE"
    },
    {
      category: "HARM_CATEGORY_SEXUALLY_EXPLICIT",
      threshold: "BLOCK_NONE"
    },
    {
      category: "HARM_CATEGORY_DANGEROUS_CONTENT",
      threshold: "BLOCK_NONE"
    }
  ]
};

// ============================================
// RETURN PREPARED DATA FOR GEMINI API NODE
// ============================================
return {
  json: {
    geminiRequestBody: geminiRequestBody,
    metadata: {
      totalCandidates: candidatesWithBase64.length,
      jobDescriptionLength: jobDescriptionText.length,
      candidates: candidatesWithBase64.map(c => ({
        number: c.candidateNumber,
        name: c.name,
        fileName: c.fileName,
        fileSizeKB: c.fileSizeKB
      })),
      processedAt: new Date().toISOString(),
      geminiModel: "gemini-1.5-pro" // or "gemini-1.5-flash" for faster processing
    },
    // Store JD separately for reference
    jobDescription: jobDescriptionText
  }
};

// ============================================
// AI RECOMMENDATIONS FORMATTER - CLAUDE AI OUTPUT
// ============================================
// Purpose: Parse Claude's JSON responses and format into Email (HTML) and Slack

const allItems = $input.all();

console.log('Total items received from Claude:', allItems.length);

// ============================================
// PARSE CLAUDE AI RESPONSES
// ============================================
const recommendations = [];

allItems.forEach((item, index) => {
  try {
    const data = item.json;

    // Claude returns the response in content array
    let claudeResponse = null;

    // Extract Claude's response from the API response structure
    if (data.content && Array.isArray(data.content)) {
      // Find the text content
      const textContent = data.content.find(c => c.type === 'text');
      if (textContent && textContent.text) {
        claudeResponse = textContent.text;
      }
    } else if (data.output) {
      claudeResponse = data.output;
    } else if (typeof data === 'string') {
      claudeResponse = data;
    }

    if (!claudeResponse) {
      console.log(`⚠ No response found for item ${index + 1}`);
      return;
    }

    console.log(`Processing candidate ${index + 1}, response length: ${claudeResponse.length}`);

    // Parse JSON from Claude's response
    // Claude might wrap JSON in markdown code blocks, so strip them
    let jsonText = claudeResponse.trim();

    // Remove markdown code blocks if present
    jsonText = jsonText.replace(/```json\n?/g, '').replace(/```\n?/g, '');

    // Parse the JSON
    const parsed = JSON.parse(jsonText);

    // Extract data from Claude's JSON structure
    recommendations.push({
      candidateNumber: index + 1,
      name: parsed.candidateName || `Candidate ${index + 1}`,
      matchScore: parsed.matchScore || 0,
      overallRecommendation: parsed.overallRecommendation || 'Not Assessed',
      keyStrengths: Array.isArray(parsed.keyStrengths) 
        ? parsed.keyStrengths.join(' • ') 
        : parsed.keyStrengths || 'N/A',
      concerns: Array.isArray(parsed.concernsGaps) 
        ? parsed.concernsGaps.join(' • ') 
        : parsed.concernsGaps || 'None identified',
      reasoning: parsed.rankingRationale || parsed.detailedNotes || 'N/A',

      // Additional details
      relevantExperience: parsed.relevantExperience || null,
      skillsAnalysis: parsed.skillsAnalysis || null,
      communicationAssessment: parsed.communicationAssessment || 'N/A',

      // Original metadata if available
      contractorId: item.json.metadata?.originalData?.contractorId || 'N/A',
      status: item.json.metadata?.originalData?.status || 'Unknown',
      availability: item.json.metadata?.originalData?.availability || 'N/A'
    });

    console.log(`✓ Parsed candidate: ${parsed.candidateName} - ${parsed.matchScore}%`);

  } catch (error) {
    console.error(`Error parsing item ${index + 1}:`, error.message);

    // Add placeholder for failed parsing
    recommendations.push({
      candidateNumber: index + 1,
      name: `Candidate ${index + 1} (Parse Error)`,
      matchScore: 0,
      overallRecommendation: 'Error',
      keyStrengths: 'Error parsing response',
      concerns: 'Could not parse AI response',
      reasoning: `Parse error: ${error.message}`
    });
  }
});

// Sort by match score (highest first)
recommendations.sort((a, b) => b.matchScore - a.matchScore);

console.log('===========================================');
console.log('Total recommendations parsed:', recommendations.length);
console.log('Top candidate:', recommendations[0]?.name);
console.log('Top score:', recommendations[0]?.matchScore);
console.log('===========================================');

// ============================================
